if (snapshot.status !== 'idle' && !('blocks' in snapshot && snapshot.blocks !== undefined)) {
  const focusedId = snapshot.status === 'editing' ? snapshot.focusedBlockId : null;
  const focusedBlockExists = focusedId ? viewState.blocks.some(b => b.id === focusedId) : true;
  if (viewState.blocks.length === 0 || !focusedBlockExists) {
    viewState = { ...viewState, blocks: [{ id: focusedId ?? 'block-default-1', type: 'paragraph', content: '' }] };
  }
}
